class TOTPGenerator:
    """Core TOTP implementation following RFC 6238."""

    def __init__(self, digits: int = 6, period: int = 30, algorithm: str = "sha1"):
        self.digits = digits
        self.period = period
        self.algorithm = algorithm

    def generate_secret(self, length: int = 20) -> str:
        """Generate a random base32-encoded secret."""
        random_bytes = os.urandom(length)
        secret = base64.b32encode(random_bytes).decode('utf-8').rstrip('=')
        return secret

    def _decode_secret(self, secret: str) -> bytes:
        """Decode a base32 secret, adding padding if necessary."""
        # Add padding if needed
        padding = 8 - (len(secret) % 8)
        if padding != 8:
            secret += '=' * padding
        return base64.b32decode(secret.upper())

    def _get_time_counter(self, timestamp: Optional[float] = None) -> int:
        """Get the time counter value for the given timestamp."""
        if timestamp is None:
            timestamp = time.time()
        return int(timestamp) // self.period

    def _hotp(self, secret_bytes: bytes, counter: int) -> str:
        """Generate HOTP value (RFC 4226)."""
        # Pack counter as 8-byte big-endian
        counter_bytes = struct.pack('>Q', counter)

        # Compute HMAC
        if self.algorithm == "sha1":
            hash_func = hashlib.sha1
        elif self.algorithm == "sha256":
            hash_func = hashlib.sha256
        elif self.algorithm == "sha512":
            hash_func = hashlib.sha512
        else:
            raise ValueError(f"Unsupported algorithm: {self.algorithm}")

        hmac_digest = hmac.new(secret_bytes, counter_bytes, hash_func).digest()

        # Dynamic truncation
        offset = hmac_digest[-1] & 0x0F
        truncated = struct.unpack('>I', hmac_digest[offset:offset + 4])[0]
        truncated &= 0x7FFFFFFF

        # Generate OTP
        otp = truncated % (10 ** self.digits)
        return str(otp).zfill(self.digits)

    def generate_totp(self, secret: str, timestamp: Optional[float] = None) -> str:
        """Generate a TOTP code for the given secret and time."""
        secret_bytes = self._decode_secret(secret)
        counter = self._get_time_counter(timestamp)
        return self._hotp(secret_bytes, counter)

    def verify_totp(self, secret: str, code: str, window: int = 1,
                    timestamp: Optional[float] = None) -> bool:
        """
        Verify a TOTP code against the secret.
        
        Args:
            secret: The base32-encoded secret
            code: The TOTP code to verify
            window: Number of time steps to check before and after current time
            timestamp: Optional timestamp to use instead of current time
            
        Returns:
            True if the code is valid within the time window
        """
        if not code or not code.isdigit() or len(code) != self.digits:
            return False

        secret_bytes = self._decode_secret(secret)
        counter = self._get_time_counter(timestamp)

        for offset in range(-window, window + 1):
            expected_code = self._hotp(secret_bytes, counter + offset)
            if hmac.compare_digest(expected_code, code):
                return True

        return False

    def get_remaining_seconds(self) -> int:
        """Get the number of seconds remaining in the current time period."""
        return self.period - (int(time.time()) % self.period)


class QRCodeGenerator:
    """Generate QR codes for authenticator app enrollment."""

    @staticmethod
    def generate_provisioning_uri(secret: str, username: str,
                                   issuer: str = "MyApp",
                                   algorithm: str = "SHA1",
                                   digits: int = 6,
                                   period: int = 30) -> str:
        """
        Generate an otpauth:// URI for provisioning authenticator apps.
        
        Format: otpauth://totp/ISSUER:USERNAME?secret=SECRET&issuer=ISSUER&algorithm=ALG&digits=D&period=P
        """
        label = f"{issuer}:{urllib.parse.quote(username)}"
        params = {
            'secret': secret,
            'issuer': issuer,
            'algorithm': algorithm,
            'digits': str(digits),
            'period': str(period),
        }
        query_string = urllib.parse.urlencode(params)
        uri = f"otpauth://totp/{label}?{query_string}"
        return uri

    @staticmethod
    def generate_qr_code(uri: str, file_path: Optional[str] = None) -> Optional[bytes]:
        """
        Generate a QR code image from a provisioning URI.
        
        Args:
            uri: The otpauth:// URI
            file_path: Optional file path to save the QR code image
            
        Returns:
            PNG image bytes if no file_path is given, None otherwise
        """
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)

        img = qr.make_image(fill_color="black", back_color="white")

        if file_path:
            img.save(file_path)
            return None
        else:
            buffer = BytesIO()
            img.save(buffer, format='PNG')
            return buffer.getvalue()

    @staticmethod
    def print_qr_code_terminal(uri: str) -> None:
        """Print QR code to terminal using ASCII characters."""
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=1,
            border=2,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        qr.print_ascii(invert=True)


class BackupCodeGenerator:
    """Generate and manage backup/recovery codes."""

    @staticmethod
    def generate_backup_codes(count: int = 10, length: int = 8) -> list:
        """Generate a set of one-time backup codes."""
        codes = []
        for _ in range(count):
            code_bytes = os.urandom(length)
            code = ''.join(f'{b:02x}' for b in code_bytes[:length // 2])
            # Format as XXXX-XXXX
            formatted = f"{code[:4]}-{code[4:]}"
            codes.append(formatted)
        return codes

    @staticmethod
    def hash_backup_code(code: str) -> str:
        """Hash a backup code for secure storage."""
        normalized = code.replace('-', '').lower()
        return hashlib.sha256(normalized.encode()).hexdigest()

    @staticmethod
    def verify_backup_code(code: str, hashed_codes: list) -> tuple:
        """
        Verify a backup code against stored hashes.
        
        Returns:
            (is_valid, index) - whether code is valid and its index for removal
        """
        code_hash = BackupCodeGenerator.hash_backup_code(code)
        for i, stored_hash in enumerate(hashed_codes):
            if hmac.compare_digest(code_hash, stored_hash):
                return True, i
        return False, -1


class MFASystem:
    """Main MFA system managing users and authentication."""

    def __init__(self, issuer: str = "MyApp", digits: int = 6,
                 period: int = 30, algorithm: str = "sha1"):
        self.issuer = issuer
        self.totp = TOTPGenerator(digits=digits, period=period, algorithm=algorithm)
        self.qr_generator = QRCodeGenerator()
        self.backup_generator = BackupCodeGenerator()
        self.users: dict[str, User] = {}

    def register_user(self, username: str, email: str) -> User:
        """Register a new user in the MFA system."""
        if username in self.users:
            raise ValueError(f"User '{username}' already exists")
        user = User(username=username, email=email)
        self.users[username] = user
        return user

    def enroll_mfa(self, username: str) -> dict:
        """
        Enroll a user in MFA.
        
        Returns:
            Dictionary containing secret, provisioning URI, QR code bytes,
            and backup codes.
        """
        user = self._get_user(username)

        # Generate TOTP secret
        secret = self.totp.generate_secret()
        user.totp_secret = secret

        # Generate provisioning URI
        uri = self.qr_generator.generate_provisioning_uri(
            secret=secret,
            username=username,
            issuer=self.issuer,
            algorithm=self.totp.algorithm.upper(),
            digits=self.totp.digits,
            period=self.totp.period,
        )

        # Generate QR code
        qr_image_bytes = self.qr_generator.generate_qr_code(uri)

        # Generate backup codes
        backup_codes = self.backup_generator.generate_backup_codes()
        user.backup_codes = [
            self.backup_generator.hash_backup_code(code) for code in backup_codes
        ]

        return {
            'secret': secret,
            'provisioning_uri': uri,
            'qr_code_png': qr_image_bytes,
            'backup_codes': backup_codes,
        }

    def activate_mfa(self, username: str, verification_code: str) -> bool:
        """
        Activate MFA for a user after they verify with a TOTP code.
        This confirms the user has set up their authenticator app correctly.
        """
        user = self._get_user(username)

        if not user.totp_secret:
            raise ValueError(f"User '{username}' has not been enrolled in MFA")

        if self.totp.verify_totp(user.totp_secret, verification_code):
            user.mfa_enabled = True
            return True
        return False

    def verify_code(self, username: str, code: str) -> dict:
        """
        Verify a TOTP code or backup code for a user.
        
        Returns:
            Dictionary with verification result and method used.
        """
        user = self._get_user(username)

        if not user.mfa_enabled:
            raise ValueError(f"MFA is not enabled for user '{username}'")

        # Try TOTP verification first
        if code.isdigit() and len(code) == self.totp.digits:
            is_valid = self.totp.verify_totp(user.totp_secret, code)
            return {
                'valid': is_valid,
                'method': 'totp',
            }

        # Try backup code verification
        is_valid, index = self.backup_generator.verify_backup_code(
            code, user.backup_codes
        )
        if is_valid:
            # Remove used backup code
            user.backup_codes.pop(index)
            return {
                'valid': True,
                'method': 'backup_code',
                'remaining_backup_codes': len(user.backup_codes),
            }

        return {
            'valid': False,
            'method': 'unknown',
        }

    def disable_mfa(self, username: str, verification_code: str) -> bool:
        """Disable MFA for a user (requires valid TOTP code)."""
        user = self._get_user(username)

        if not user.mfa_enabled:
            raise ValueError(f"MFA is not enabled for user '{username}'")

        if self.totp.verify_totp(user.totp_secret, verification_code):
            user.mfa_enabled = False
            user.totp_secret = None
            user.backup_codes = []
            return True
        return False

    def regenerate_backup_codes(self, username: str, verification_code: str) -> Optional[list]:
        """Regenerate backup codes for a user (requires valid TOTP code)."""
        user = self._get_user(username)

        if not user.mfa_enabled:
            raise ValueError(f"MFA is not enabled for user '{username}'")

        if self.totp.verify_totp(user.totp_secret, verification_code):
            backup_codes = self.backup_generator.generate_backup_codes()
            user.backup_codes = [
                self.backup_generator.hash_backup_code(code) for code in backup_codes
            ]
            return backup_codes
        return None

    def get_user_mfa_status(self, username: str) -> dict:
        """Get the MFA status for a user."""
        user = self._get_user(username)
        return {
            'username': user.username,
            'mfa_enabled': user.mfa_enabled,
            'has_secret': user.totp_secret is not None,
            'backup_codes_remaining': len(user.backup_codes),
        }

    def _get_user(self, username: str) -> User:
        """Get a user by username or raise an error."""
        if username not in self.users:
            raise ValueError(f"User '{username}' not found")
        return self.users[username]


